import React, { useEffect, useState } from 'react';
import { useSearchParams } from 'react-router-dom';
import { getGoogleUserInfo } from '../services/googleAuth';
import { showNotification } from '../assets/notifications';
import { formatWelcomeMessage } from '../utils/nameFormatter';
import { useNavigationWithDelay } from '../hooks/useNavigationWithDelay';
import { userAPI } from '../services/userAPI';
import { useAuth } from '../context/AuthContext';
import Loading from '../components/Loading';

const GoogleCallback: React.FC = () => {
  const [searchParams] = useSearchParams();
  const { isLoading, redirectWithDelay } = useNavigationWithDelay();
  const { googleLoginSuccess } = useAuth();

  useEffect(() => {
    const handleGoogleCallback = async () => {
      try {
        const code = searchParams.get('code');
        const error = searchParams.get('error');

        if (error) {
          console.error('Google OAuth error:', error);
          window.location.href = '/?error=google_auth_failed';
          return;
        }

        if (!code) {
          console.error('No authorization code received');
          window.location.href = '/?error=no_code_received';
          return;
        }

        console.log('Received Google auth code:', code);

        // الحصول على بيانات Google الفعلية من Backend
        const googleUserData = await getGoogleUserInfo(code);
        console.log('Google user data:', googleUserData);

        const existingUsers = JSON.parse(localStorage.getItem('users') || '[]');
        let googleUser = existingUsers.find((u: any) => u.email === googleUserData.email);

        if (googleUser) {
          // المستخدم موجود بالفعل - جلب البيانات المحدثة من API ثم تسجيل الدخول
          console.log('Found existing user in storage:', googleUser);

          // جلب البيانات المحدثة من userAPI
          const updatedUser = await userAPI.getUserById(googleUser._id);
          const userToUse = updatedUser || googleUser;

          console.log('Using updated user data for login:', userToUse);
          console.log('Calling googleLoginSuccess with user:', userToUse);

          // Debug data consistency before login
          userAPI.debugUserData(userToUse._id);

          await googleLoginSuccess(userToUse);
          console.log('googleLoginSuccess completed');
        } else {
          // مستخدم جديد عبر Google - إنشاء حساب جديد ثم تسجيل الدخول
          const newUser = await userAPI.createUser({
            email: googleUserData.email,
            firstName: googleUserData.firstName,
            lastName: googleUserData.lastName,
            role: 'user'
          });

          console.log('New user created via Google:', newUser);
          console.log('Calling googleLoginSuccess with new user:', newUser);
          await googleLoginSuccess(newUser);
          console.log('googleLoginSuccess completed for new user');
        }
      } catch (error) {
        console.error('Callback error:', error);
        showNotification('فشل تسجيل الدخول عبر Google. يرجى المحاولة مرة أخرى.', 'error');
        window.location.href = '/?error=callback_failed';
      }
    };

    handleGoogleCallback();
  }, [searchParams, googleLoginSuccess]);

  return (
    <>
      {isLoading && <Loading />}
      <div className="min-h-screen flex items-center justify-center" style={{ backgroundColor: '#0a0a0a' }}>
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-red-600 mx-auto mb-4"></div>
          <p className="text-white text-lg">جاري تسجيل الدخول...</p>
          <p className="text-gray-400 text-sm mt-2">يرجى الانتظار</p>
        </div>
      </div>
    </>
  );
};

export default GoogleCallback;
